import { describe, it, expect } from "vitest";
import type { MilestoneInfo } from "@/lib/types";
import {
  groupMilestonesByStatus,
  filterMilestonesByStatus,
  getStatusCounts,
  type StatusFilter,
} from "@/lib/milestone-filters";

// ---------------------------------------------------------------------------
// Test fixtures — milestones covering all CompletionStatus values
// ---------------------------------------------------------------------------

const milestones: MilestoneInfo[] = [
  {
    id: "M001",
    title: "Scaffolding",
    status: "done",
    cost: 2.4,
    progress: 100,
    slices: [],
  },
  {
    id: "M002",
    title: "Backend Bridge",
    status: "in-progress",
    cost: 3.1,
    progress: 50,
    slices: [],
  },
  {
    id: "M003",
    title: "Dashboard",
    status: "pending",
    cost: 0,
    progress: 0,
    slices: [],
  },
  {
    id: "M004",
    title: "Analytics",
    status: "blocked",
    cost: 0,
    progress: 0,
    slices: [],
  },
  {
    id: "M005",
    title: "Polish",
    status: "done",
    cost: 1.2,
    progress: 100,
    slices: [],
  },
];

// ---------------------------------------------------------------------------
// groupMilestonesByStatus
// ---------------------------------------------------------------------------

describe("groupMilestonesByStatus", () => {
  it("returns empty array for empty input", () => {
    expect(groupMilestonesByStatus([])).toEqual([]);
  });

  it("returns one group when all milestones share a status category", () => {
    const doneMilestones = milestones.filter((m) => m.status === "done");
    const groups = groupMilestonesByStatus(doneMilestones);
    expect(groups).toHaveLength(1);
    expect(groups[0].label).toBe("Complete");
    expect(groups[0].milestones).toHaveLength(2);
  });

  it("groups mixed statuses into Active, Complete, and Planned", () => {
    const groups = groupMilestonesByStatus(milestones);
    const labels = groups.map((g) => g.label);
    expect(labels).toContain("Active");
    expect(labels).toContain("Complete");
    expect(labels).toContain("Planned");
  });

  it("puts in-progress milestones in the Active group", () => {
    const groups = groupMilestonesByStatus(milestones);
    const active = groups.find((g) => g.label === "Active")!;
    expect(active.milestones.map((m) => m.id)).toEqual(["M002"]);
  });

  it("puts done milestones in the Complete group", () => {
    const groups = groupMilestonesByStatus(milestones);
    const complete = groups.find((g) => g.label === "Complete")!;
    expect(complete.milestones.map((m) => m.id)).toEqual(["M001", "M005"]);
  });

  it("groups blocked milestones with planned (pending) in the Planned group", () => {
    const groups = groupMilestonesByStatus(milestones);
    const planned = groups.find((g) => g.label === "Planned")!;
    expect(planned.milestones.map((m) => m.id)).toEqual(["M003", "M004"]);
  });

  it("omits groups with no milestones", () => {
    const onlyDone = milestones.filter((m) => m.status === "done");
    const groups = groupMilestonesByStatus(onlyDone);
    expect(groups).toHaveLength(1);
    expect(groups[0].label).toBe("Complete");
  });

  it("each group includes the matching CompletionStatus values", () => {
    const groups = groupMilestonesByStatus(milestones);
    const active = groups.find((g) => g.label === "Active")!;
    expect(active.status).toEqual(["in-progress"]);
    const planned = groups.find((g) => g.label === "Planned")!;
    expect(planned.status).toEqual(["pending", "blocked"]);
  });
});

// ---------------------------------------------------------------------------
// filterMilestonesByStatus
// ---------------------------------------------------------------------------

describe("filterMilestonesByStatus", () => {
  it("returns all milestones for 'all' filter", () => {
    const result = filterMilestonesByStatus(milestones, "all");
    expect(result).toHaveLength(5);
  });

  it("returns only in-progress milestones for 'active' filter", () => {
    const result = filterMilestonesByStatus(milestones, "active");
    expect(result.map((m) => m.id)).toEqual(["M002"]);
  });

  it("returns only done milestones for 'complete' filter", () => {
    const result = filterMilestonesByStatus(milestones, "complete");
    expect(result.map((m) => m.id)).toEqual(["M001", "M005"]);
  });

  it("returns pending and blocked milestones for 'planned' filter", () => {
    const result = filterMilestonesByStatus(milestones, "planned");
    expect(result.map((m) => m.id)).toEqual(["M003", "M004"]);
  });

  it("returns empty array when no milestones match the filter", () => {
    const onlyDone = milestones.filter((m) => m.status === "done");
    const result = filterMilestonesByStatus(onlyDone, "active");
    expect(result).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// getStatusCounts
// ---------------------------------------------------------------------------

describe("getStatusCounts", () => {
  it("returns correct counts for each category", () => {
    const counts = getStatusCounts(milestones);
    expect(counts).toEqual({
      all: 5,
      active: 1,
      complete: 2,
      planned: 2,
    });
  });

  it("returns all zeros for empty input", () => {
    const counts = getStatusCounts([]);
    expect(counts).toEqual({ all: 0, active: 0, complete: 0, planned: 0 });
  });

  it("counts only the present statuses", () => {
    const onlyDone = milestones.filter((m) => m.status === "done");
    const counts = getStatusCounts(onlyDone);
    expect(counts).toEqual({ all: 2, active: 0, complete: 2, planned: 0 });
  });
});

import type { MilestoneInfo, CompletionStatus } from "@/lib/types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Filter value for the milestone filter bar. */
export type StatusFilter = "all" | "active" | "complete" | "planned";

/** A group of milestones sharing the same status category. */
export interface StatusGroup {
  label: string;
  status: CompletionStatus[];
  milestones: MilestoneInfo[];
}

// ---------------------------------------------------------------------------
// Category definitions
// ---------------------------------------------------------------------------

interface CategoryDef {
  label: string;
  status: CompletionStatus[];
}

const categories: CategoryDef[] = [
  { label: "Active", status: ["in-progress"] },
  { label: "Complete", status: ["done"] },
  { label: "Planned", status: ["pending", "blocked"] },
];

const filterToStatuses: Record<StatusFilter, CompletionStatus[] | null> = {
  all: null,
  active: ["in-progress"],
  complete: ["done"],
  planned: ["pending", "blocked"],
};

// ---------------------------------------------------------------------------
// Functions
// ---------------------------------------------------------------------------

/**
 * Group milestones by status category: Active (in-progress), Complete (done),
 * and Planned (pending + blocked). Returns only non-empty groups in a stable
 * order: Active → Complete → Planned.
 */
export function groupMilestonesByStatus(
  milestones: MilestoneInfo[],
): StatusGroup[] {
  if (milestones.length === 0) return [];

  const groups: StatusGroup[] = [];

  for (const cat of categories) {
    const matched = milestones.filter((m) => cat.status.includes(m.status));
    if (matched.length > 0) {
      groups.push({
        label: cat.label,
        status: cat.status,
        milestones: matched,
      });
    }
  }

  return groups;
}

/**
 * Filter milestones by status category. Returns all milestones for 'all',
 * or the subset matching the given filter.
 */
export function filterMilestonesByStatus(
  milestones: MilestoneInfo[],
  filter: StatusFilter,
): MilestoneInfo[] {
  const statuses = filterToStatuses[filter];
  if (statuses === null) return milestones;
  return milestones.filter((m) => statuses.includes(m.status));
}

/**
 * Count milestones per filter category for badge display.
 */
export function getStatusCounts(
  milestones: MilestoneInfo[],
): Record<StatusFilter, number> {
  const counts: Record<StatusFilter, number> = {
    all: milestones.length,
    active: 0,
    complete: 0,
    planned: 0,
  };

  for (const m of milestones) {
    switch (m.status) {
      case "in-progress":
        counts.active++;
        break;
      case "done":
        counts.complete++;
        break;
      case "pending":
      case "blocked":
        counts.planned++;
        break;
    }
  }

  return counts;
}

import { describe, it, expect, vi } from "vitest";
import { renderWithProviders, screen } from "@/test/test-utils";
import userEvent from "@testing-library/user-event";
import { MilestoneFilterBar } from "@/components/milestones/milestone-filter-bar";
import type { StatusFilter } from "@/lib/milestone-filters";

const defaultCounts: Record<StatusFilter, number> = {
  all: 5,
  active: 1,
  complete: 2,
  planned: 2,
};

function renderBar(
  overrides: {
    counts?: Record<StatusFilter, number>;
    activeFilter?: StatusFilter;
    onChange?: (f: StatusFilter) => void;
  } = {},
) {
  const onChange = overrides.onChange ?? vi.fn();
  return {
    onChange,
    ...renderWithProviders(
      <MilestoneFilterBar
        counts={overrides.counts ?? defaultCounts}
        activeFilter={overrides.activeFilter ?? "all"}
        onChange={onChange}
      />,
    ),
  };
}

describe("MilestoneFilterBar", () => {
  it("renders All, Active, Complete, and Planned buttons", () => {
    renderBar();
    expect(screen.getByRole("button", { name: /all/i })).toBeInTheDocument();
    expect(screen.getByRole("button", { name: /active/i })).toBeInTheDocument();
    expect(
      screen.getByRole("button", { name: /complete/i }),
    ).toBeInTheDocument();
    expect(
      screen.getByRole("button", { name: /planned/i }),
    ).toBeInTheDocument();
  });

  it("'All' button is pressed by default", () => {
    renderBar({ activeFilter: "all" });
    const allBtn = screen.getByRole("button", { name: /all/i });
    expect(allBtn).toHaveAttribute("data-active", "true");
  });

  it("the active filter button has data-active='true', others do not", () => {
    renderBar({ activeFilter: "active" });
    expect(screen.getByRole("button", { name: /^active/i })).toHaveAttribute(
      "data-active",
      "true",
    );
    expect(screen.getByRole("button", { name: /all/i })).toHaveAttribute(
      "data-active",
      "false",
    );
    expect(screen.getByRole("button", { name: /complete/i })).toHaveAttribute(
      "data-active",
      "false",
    );
  });

  it("clicking a filter calls onChange with the correct StatusFilter", async () => {
    const user = userEvent.setup();
    const { onChange } = renderBar();

    await user.click(screen.getByRole("button", { name: /complete/i }));
    expect(onChange).toHaveBeenCalledWith("complete");

    await user.click(screen.getByRole("button", { name: /planned/i }));
    expect(onChange).toHaveBeenCalledWith("planned");
  });

  it("displays counts as badge text on each button", () => {
    renderBar();
    // Each button should contain its count
    expect(screen.getByRole("button", { name: /all/i })).toHaveTextContent(
      "5",
    );
    expect(screen.getByRole("button", { name: /active/i })).toHaveTextContent(
      "1",
    );
    expect(
      screen.getByRole("button", { name: /complete/i }),
    ).toHaveTextContent("2");
    expect(
      screen.getByRole("button", { name: /planned/i }),
    ).toHaveTextContent("2");
  });

  it("renders zero counts without crashing", () => {
    const zeroCounts: Record<StatusFilter, number> = {
      all: 0,
      active: 0,
      complete: 0,
      planned: 0,
    };
    renderBar({ counts: zeroCounts });
    expect(screen.getByRole("button", { name: /all/i })).toHaveTextContent(
      "0",
    );
  });
});

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { StatusFilter } from "@/lib/milestone-filters";
import { cn } from "@/lib/utils";

const filters: { value: StatusFilter; label: string }[] = [
  { value: "all", label: "All" },
  { value: "active", label: "Active" },
  { value: "complete", label: "Complete" },
  { value: "planned", label: "Planned" },
];

interface MilestoneFilterBarProps {
  counts: Record<StatusFilter, number>;
  activeFilter: StatusFilter;
  onChange: (filter: StatusFilter) => void;
}

export function MilestoneFilterBar({
  counts,
  activeFilter,
  onChange,
}: MilestoneFilterBarProps) {
  return (
    <div className="flex items-center gap-2" role="group" aria-label="Filter milestones by status">
      {filters.map(({ value, label }) => {
        const isActive = activeFilter === value;
        return (
          <Button
            key={value}
            variant={isActive ? "default" : "outline"}
            size="sm"
            data-active={isActive}
            onClick={() => onChange(value)}
            className={cn(
              "gap-1.5",
              !isActive && "text-muted-foreground",
            )}
          >
            {label}
            <Badge
              variant={isActive ? "secondary" : "outline"}
              className="ml-0.5 px-1.5 py-0 text-[10px] leading-4"
            >
              {counts[value]}
            </Badge>
          </Button>
        );
      })}
    </div>
  );
}
